const [form, setForm] = useState<QuicklinkFormState>(() => 
  quicklink ? { name: quicklink.name, ... } : INITIAL_FORM
);
const [errors, setErrors] = useState<Partial<Record<keyof QuicklinkFormState, string>>>({});

const handleSubmit = useCallback(() => {
